 * Redis cache client using Upstash REST API.
 *
 * Uses UPSTASH_REDIS_REST_URL + UPSTASH_REDIS_REST_TOKEN when available
 * (production), falls back to an in-memory LRU cache (dev / preview).
 *
 * Designed for server-only use — cache-invalidation-sensitive operations
 * (e.g., business data lookups) with a stale-while-revalidate pattern.
 *
 * The existing rate-limit.ts uses the same Upstash env vars, so this
 * shares configuration with no additional setup.
 */

import 'server-only'
import { LRUCache } from 'lru-cache'
import { logger } from '@/lib/logger'
import { metrics } from '@/lib/obs/metrics'

// [REDACTED_TOKEN]------------
// Types
// [REDACTED_TOKEN]------------

export interface CacheEntry<T> {
  value: T
  staleAt: number // unix ms — after this, serve stale + revalidate in bg
  expiresAt: number // unix ms — hard expiry, serve nothing after this
}

export interface CacheOptions {
  /** Time-to-live in ms before the entry becomes stale (default 60s). */
  ttl: number
  /** Hard expiry in ms — beyond this the key is evicted entirely (default 5min). */
  maxAge: number
}

const DEFAULT_OPTIONS: CacheOptions = {
  ttl: 60_000,       // 1 minute fresh
  maxAge: 300_000,   // 5 minutes hard expiry
}

// [REDACTED_TOKEN]------------
// Upstash REST client
// [REDACTED_TOKEN]------------

function getUpstashConfig(): { url: string; token: string } | null {
  const url = process.env.UPSTASH_REDIS_REST_URL
  const token = process.env.UPSTASH_REDIS_REST_TOKEN
  if (url && token) return { url, token }
  return null
}

async function upstashGet<T>(key: string): Promise<CacheEntry<T> | null> {
  const config = getUpstashConfig()
  if (!config) return null

  try {
    const res = await fetch(`${config.url}/get/${encodeURIComponent(key)}`, {
      method: 'POST',
      headers: { Authorization: `Bearer ${config.token}` },
      // The stale data is still useful; short timeout is acceptable
      signal: AbortSignal.timeout(2_000),
    })
    const json = (await res.json()) as { result?: string }
    if (!json.result) return null
    return JSON.parse(json.result) as CacheEntry<T>
  } catch {
    return null
  }
}

async function upstashSet<T>(
  key: string,
  entry: CacheEntry<T>,
  options: CacheOptions,
): Promise<void> {
  const config = getUpstashConfig()
  if (!config) return

  try {
    const body = JSON.stringify(entry)
    await fetch(`${config.url}/set/${encodeURIComponent(key)}/${encodeURIComponent(body)}`, {
      method: 'POST',
      headers: { Authorization: `Bearer ${config.token}` },
      signal: AbortSignal.timeout(2_000),
    })
    // Set TTL to maxAge so Redis auto-evicts
    await fetch(
      `${config.url}/expire/${encodeURIComponent(key)}/${Math.ceil(options.maxAge / 1000)}`,
      {
        method: 'POST',
        headers: { Authorization: `Bearer ${config.token}` },
        signal: AbortSignal.timeout(1_000),
      },
    )
  } catch {
    // Best-effort — cache miss on next read is acceptable
  }
}

async function upstashDel(key: string): Promise<void> {
  const config = getUpstashConfig()
  if (!config) return

  try {
    await fetch(`${config.url}/del/${encodeURIComponent(key)}`, {
      method: 'POST',
      headers: { Authorization: `Bearer ${config.token}` },
      signal: AbortSignal.timeout(1_000),
    })
  } catch {
    // Best-effort
  }
}

// [REDACTED_TOKEN]------------
// In-memory LRU fallback
// [REDACTED_TOKEN]------------

const MEM_CACHE = new LRUCache<string, CacheEntry<unknown>>({
  max: 500,
  ttlAutopurge: true,
})

function memGet<T>(key: string): CacheEntry<T> | undefined {
  return MEM_CACHE.get(key) as CacheEntry<T> | undefined
}

function memSet<T>(key: string, entry: CacheEntry<T>): void {
  MEM_CACHE.set(key, entry)
}

function memDel(key: string): void {
  MEM_CACHE.delete(key)
}

// [REDACTED_TOKEN]------------
// Public API
// [REDACTED_TOKEN]------------

/**
 * Retrieve a value from cache. Returns `null` on cache miss or hard expiry.
 */
async function get<T>(key: string): Promise<CacheEntry<T> | null> {
  const upstash = getUpstashConfig()
  if (upstash) {
    const entry = await upstashGet<T>(key)
    if (entry) {
      if (Date.now() < entry.expiresAt) return entry
      metrics.increment('cache.hard_expired', 1)
      await upstashDel(key)
      return null
    }
    return null
  }

  const entry = memGet<T>(key)
  if (!entry) return null
  if (Date.now() < entry.expiresAt) return entry
  metrics.increment('cache.hard_expired', 1)
  memDel(key)
  return null
}

/**
 * Write a value to cache with fresh/stale/expire windows.
 */
async function set<T>(
  key: string,
  value: T,
  options: Partial<CacheOptions> = {},
): Promise<void> {
  const opts = { ...DEFAULT_OPTIONS, ...options }
  const now = Date.now()
  const entry: CacheEntry<T> = {
    value,
    staleAt: now + opts.ttl,
    expiresAt: now + opts.maxAge,
  }

  const upstash = getUpstashConfig()
  if (upstash) {
    await upstashSet(key, entry, opts)
  } else {
    memSet(key, entry)
  }
}

/**
 * Invalidate a cached key.
 */
async function del(key: string): Promise<void> {
  const upstash = getUpstashConfig()
  if (upstash) {
    await upstashDel(key)
  } else {
    memDel(key)
  }
}

/**
 * Fetch + cache with stale-while-revalidate semantics.
 *
 * Returns stale data immediately if available, then refreshes in the
 * background. If no cached data exists, waits for the fresh fetch.
 */
export async function fetchWithStaleWhileRevalidate<T>(
  key: string,
  fetcher: () => Promise<T>,
  options: Partial<CacheOptions> = {},
): Promise<T> {
  const opts = { ...DEFAULT_OPTIONS, ...options }

  // 1. Try cache
  const cached = await get<T>(key)
  if (cached) {
    if (Date.now() < cached.staleAt) {
      // Fresh — return immediately
      metrics.increment('cache.hit_fresh', 1)
      return cached.value
    }

    // Stale — return stale, revalidate in background
    metrics.increment('cache.hit_stale', 1)
    // Background revalidation — fire and forget
    revalidateInBackground(key, fetcher, opts)
    return cached.value
  }

  metrics.increment('cache.miss', 1)

  // 2. Cache miss — fetch synchronously and cache
  try {
    const value = await fetcher()
    await set(key, value, opts)
    return value
  } catch (err) {
    // Let caller handle fetcher errors
    throw err
  }
}

/**
 * Revalidate a cache entry in the background (fire-and-forget).
 */
async function revalidateInBackground<T>(
  key: string,
  fetcher: () => Promise<T>,
  options: CacheOptions,
): Promise<void> {
  try {
    const value = await fetcher()
    await set(key, value, options)
  } catch (err) {
    logger.warn('Background cache revalidation failed', {
      action: 'revalidateInBackground',
      key,
      error: err instanceof Error ? err.message : String(err),
    })
    // Keep serving stale data — don't invalidate on revalidation failure
  }
}

export const redis = { get, set, del, fetchWithStaleWhileRevalidate }
